def extract_relevant_diff(diff: str, line: int, context_lines: int = 3) -> str:
    """
    Extract the diff hunk that contains or is closest to a given line.
    """
    lines = diff.splitlines()
    hunk = []
    in_hunk = False
    hunk_start = None
    hunk_end = None

    for i, l in enumerate(lines):
        if l.startswith("@@"):
            parts = l.split()
            for p in parts:
                if p.startswith("+"):
                    start = int(p.split(",")[0][1:])
                    length = int(p.split(",")[1]) if "," in p else 1
                    hunk_start = start
                    hunk_end = start + length
            in_hunk = hunk_start <= line <= hunk_end
            hunk = [l] if in_hunk else []
        elif in_hunk:
            hunk.append(l)

    return "\n".join(hunk)

def destructive_change_detected(original: str, patched: str) -> bool:
    original_loc = count_non_comment_lines(original)
    patched_loc = count_non_comment_lines(patched)

    if original_loc == 0:
        return False

    # Major LOC reduction
    if patched_loc < original_loc * 0.7:
        return True

    # Executable line replaced by comment
    diff = list(difflib.unified_diff(
        original.splitlines(),
        patched.splitlines(),
        lineterm=""
    ))

    for line in diff:
        if line.startswith("-") and not line.startswith("---"):
            removed_line = line[1:].strip()
            if removed_line and not removed_line.startswith(("#", "//")):
                # Check if corresponding added line is comment
                # Simple heuristic: next line in diff
                # (Not perfect but effective)
                continue

    return False

def count_non_comment_lines(text: str) -> int:
    lines = text.splitlines()
    count = 0
    for line in lines:
        stripped = line.strip()
        # Slightly scuffed condition but should hold generally
        if stripped and not stripped.startswith(("#", "//", "/*", "*")):
            count += 1
    return count

def fingerprint(findings):
    return {
        (
            f.get("check_id"),
            f.get("start", {}).get("line")
        )
        for f in findings
    }

def format_findings(findings):
    formatted = []

    for f in findings:
        check_id = f.get("check_id")
        message = f.get("extra", {}).get("message", "")
        line = f.get("start", {}).get("line", "?")
        snippet = f.get("extra", {}).get("lines", "").strip()

        formatted.append(
            f"""Rule: {check_id}
            Line: {line}
            Message: {message}
            Code:
            {snippet}
            """
        )

    return "\n---\n".join(formatted)

int main(int argc, char **argv) {
    if (argc < 2) return 1;
    step1(argv[1]);     
    return 0;
}

static void vulnerable_copy(const char *s) {
    char buf[16];
    strcpy(buf, s);  // VULNERABLE: no bounds check
    printf("buf=%s\n", buf);
}

static void step2(const char *s) {
    // just another hop in the call chain
    vulnerable_copy(s);
}

static void step1(const char *s) {
    log_input(s);
    step2(s);
}

static void log_input(const char *s) {
    printf("input length=%zu\n", strlen(s));
}

