def callee_name_from_text(s: str) -> str:
    s = (s or "").strip()
    if not s:
        return ""
    for sep in ("::", ".", "->"):
        if sep in s:
            s = s.split(sep)[-1]
    return s.strip().rstrip("(").strip()

