def load_language(lib_path: str, name: str) -> Language:
    lib = _LIBS.get(lib_path)
    if lib is None:
        lib = ctypes.CDLL(lib_path)
        _LIBS[lib_path] = lib
    fn = getattr(lib, f"tree_sitter_{name}")
    fn.restype = ctypes.c_void_p
    return Language(fn())

def make_callsite_id(caller_key: str, call_line: int, callee_text: str) -> str:
    h = hashlib.sha1(callee_text.encode("utf-8", errors="replace")).hexdigest()[:12]
    return f"{caller_key}::{call_line}::{h}"

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument(
        "--repo",
        default=".",
        help="Local repo path to scan (default: git root if inside a repo)",
    )
    ap.add_argument(
        "--git", default=None, help="Git URL/path to clone+scan (overrides --repo)"
    )
    ap.add_argument("--out", default="-", help="Output JSONL file (default: stdout)")
    args = ap.parse_args()

    temp_dir = None
    if args.git:
        # Clone then scan clone root
        if is_git_url(args.git) or not os.path.isdir(args.git):
            temp_dir = clone_to_temp(args.git)
            repo_root = os.path.abspath(temp_dir)
        else:
            repo_root = os.path.abspath(args.git)
    else:
        # If --repo is '.', scan git root (not just current subdir)
        repo_root = (
            get_git_root(args.repo) if args.repo == "." else os.path.abspath(args.repo)
        )

    data, stats = parse_repo(repo_root)

    if args.out == "-":
        for rec in data:
            print(json.dumps(rec, ensure_ascii=False))
    else:
        with open(args.out, "w", encoding="utf-8") as out_f:
            for rec in data:
                print(json.dumps(rec, ensure_ascii=False), file=out_f)

    print(
        json.dumps({"_stats": stats, "repo_root": repo_root}, ensure_ascii=False),
        file=sys.stderr,
    )

    if temp_dir:
        shutil.rmtree(temp_dir, ignore_errors=True)

