    return scan_with_semgrep(repo_path=repo_path, configs=configs)

def _filter_findings_to_changed_lines(
    findings: List[Dict],
    changed_ranges: Dict[str, List[Tuple[int, int]]],
) -> List[Dict]:
    if not findings or not changed_ranges:
        return []

    def _line_in_ranges(line: int, ranges: List[Tuple[int, int]]) -> bool:
        for start, end in ranges:
            if start <= line <= end:
                return True
        return False

    filtered: List[Dict] = []
    for f in findings:
        path = f.get("path")
        line = f.get("start", {}).get("line")
        if not path or not line:
            continue
        ranges = changed_ranges.get(path)
        if not ranges:
            continue
        if _line_in_ranges(line, ranges):
            filtered.append(f)

    return filtered

def _line_in_ranges(line: int, ranges: List[Tuple[int, int]]) -> bool:
        for start, end in ranges:
            if start <= line <= end:
                return True
        return False

def _get_changed_line_ranges(
    base_ref: str,
    head_ref: str,
    repo_path: str = ".",
) -> Dict[str, List[Tuple[int, int]]]:
    proc = run_git(["diff", "-U0", f"{base_ref}..{head_ref}"], repo_path)
    return _parse_changed_line_ranges(proc.stdout or "")

def _parse_changed_line_ranges(diff_text: str) -> Dict[str, List[Tuple[int, int]]]:
    """
    Parse unified diff text and return added/modified line ranges per file.

    Returns:
        { "path/to/file.py": [(start_line, end_line), ...], ... }
    """
    ranges: Dict[str, List[Tuple[int, int]]] = defaultdict(list)
    current_file: Optional[str] = None

    for line in diff_text.splitlines():
        if line.startswith("diff --git "):
            current_file = None
            continue

        if line.startswith("+++ "):
            path = line[4:].strip()
            if path == "/dev/null":
                current_file = None
                continue
            if path.startswith("b/"):
                path = path[2:]
            current_file = path
            continue

        if line.startswith("@@") and current_file:
            # Example: @@ -12,0 +13,5 @@
            m = re.search(r"\+(\d+)(?:,(\d+))?", line)
            if not m:
                continue
            start = int(m.group(1))
            length = int(m.group(2) or "1")
            if length <= 0:
                continue
            ranges[current_file].append((start, start + length - 1))

    return ranges

def print_findings(findings: List[Dict]) -> None:
    """Print grouped, human-friendly details for a list of semgrep findings.

    Shows the matched source lines (with context) when the file is available.
    """
    # Accept either a flat list of findings or a grouped dict {file: [findings]}
    if isinstance(findings, dict):
        grouped = findings
    else:
        grouped = group_findings_by_file(findings)
    for file, file_findings in grouped.items():
        print(file)

        # Try to load the source file for context printing
        full_path = file if os.path.isabs(file) else os.path.join(os.getcwd(), file)
        file_lines = None
        if os.path.exists(full_path):
            try:
                with open(full_path, "r", encoding="utf-8", errors="replace") as fh:
                    file_lines = fh.read().splitlines()
            except Exception:
                file_lines = None

        for f in file_findings:
            rule = f.get("check_id") or f.get("rule") or f.get("rule_id") or "unknown-rule"
            start_line = f.get("start", {}).get("line")
            end_line = f.get("end", {}).get("line") or start_line
            extra = f.get("extra", {}) or {}
            message = extra.get("message") or f.get("message") or ""
            severity = extra.get("severity") or f.get("severity") or ""
            snippet = extra.get("lines") or extra.get("code") or None

            out = f"  - {rule}: line={start_line} severity={severity} message={message}"
            print(out)

            # If we have the file content, print a small context block
            if file_lines and start_line:
                ctx = 2
                a = max(1, start_line - ctx)
                b = min(len(file_lines), (end_line or start_line) + ctx)
                print("    snippet:")
                for ln in range(a, b + 1):
                    mark = ">>" if start_line and end_line and (ln >= start_line and ln <= end_line) else "  "
                    line_text = file_lines[ln - 1]
                    print(f"      {mark} {ln:4d}: {line_text}")
            else:
                if snippet:
                    print("    snippet:")
                    for ln in (snippet.splitlines() if isinstance(snippet, str) else [snippet]):
                        print(f"      {ln}")

def scan_paths(
    paths: List[str],
    repo_root: str = ".",
    configs: Optional[List[str]] = None,
) -> List[Dict]:
    """Scan a list of file paths (relative to repo_root or absolute).

    Runs a single semgrep process with all valid paths (faster than per-file).
    Skips paths that do not exist and falls back to per-file scanning on error.
    Returns a flat list of semgrep result dicts.
    """
    if not configs:
        configs = ["p/security-audit"]

    valid_rel_paths: List[str] = []
    for p in paths:
        full = p if os.path.isabs(p) else os.path.join(repo_root, p)
        if not os.path.exists(full):
            continue
        # keep paths relative to the repo root so semgrep output paths match git diff keys
        rel = os.path.relpath(full, repo_root) if repo_root and os.path.isdir(repo_root) else full
        valid_rel_paths.append(rel)

    if not valid_rel_paths:
        return []

    # Try a single batched semgrep invocation first (uses semgrep's internal multiprocessing).
    try:
        return scan_with_semgrep(repo_path=repo_root, configs=configs, paths=valid_rel_paths)
    except Exception:
        # If batching fails, fall back to the previous per-file behavior.
        results: List[Dict] = []
        for rel in valid_rel_paths:
            try:
                file_results = scan_with_semgrep(repo_path=os.path.join(repo_root, rel), configs=configs)
            except Exception:
                # skip files that cause semgrep/config errors
                continue
            if file_results:
                results.extend(file_results)
        return results

def scan_code_string(
    code: str,
    configs: Optional[List[str]] = None,
    language: str = "python"
) -> List[Dict]:
    """Scan a code string directly without needing a repo path"""
    if not configs:
        configs = ["p/security-audit"]

    # Create temp file with code
    with tempfile.NamedTemporaryFile(mode='w', suffix=f'.{language}', delete=False) as f:
        f.write(code)
        temp_path = f.name

    try:
        cmd = ["semgrep", "scan", "--quiet", "--json"]
        for c in configs:
            cmd += ["--config", c]
        cmd.append(temp_path)

        p = subprocess.run(cmd, capture_output=True, text=True)

        if p.returncode not in (0, 1):
            raise RuntimeError(f"Semgrep failed: {p.stderr}")

        if not p.stdout.strip():
            return []

        return json.loads(p.stdout).get("results", [])
    finally:
        os.unlink(temp_path)

def group_findings_by_file(findings: List[Dict]) -> Dict[str, List[Dict]]:
    grouped = defaultdict(list)
    for finding in findings:
        grouped[finding["path"]].append(finding)
    return grouped

def new(self) -> str:
        """First 'new' snippet (for backward compatibility)."""
        return self.replacements[0][1] if self.replacements else ""

def old(self) -> str:
        """First 'old' snippet (for backward compatibility)."""
        return self.replacements[0][0] if self.replacements else ""

def trunc(s: str, n: int) -> str:
        if len(s) <= n:
            return s
        return s[:n] + "\n... [truncated]"

def _truthy_env(name: str) -> bool:
    _ensure_dotenv()
    return os.environ.get(name, "").strip().lower() in ("1", "true", "yes", "on")

def _ensure_dotenv() -> None:
    """So DEBUG_LLM_CONTEXT in .env works even if nothing called load_dotenv yet."""
    global _dotenv_loaded
    if _dotenv_loaded:
        return
    _dotenv_loaded = True
    try:
        from dotenv import load_dotenv

        load_dotenv()
    except ImportError:
        pass

def run(self, context):
        file = context["file"]
        finding = context["finding"]
        diff = context.get("diff", "")
        previous_failures = context.get("previous_failures", [])
        failure_msg = "\n".join(previous_failures)

        sys = f"""
You are a security-focused code remediation agent.

Your task:
- Make minimal changes to fix the vulnerability.
- You may add imports or helper code if strictly necessary to make the fix valid.
- Do NOT rewrite unrelated logic.
- Each "old" snippet MUST appear verbatim in the file.
- Do NOT simply comment out the old code; your fix must preserve program logic.
- Only remove or replace code in a way that keeps the function/file operational.

Output only JSON in one of these formats:

Single replacement:
{{
  "old": "<exact code snippet to replace>",
  "new": "<secure replacement code snippet>",
  "risk": "low | medium | high"
}}

Multiple replacements (use when the fix requires several edits in the same file, e.g. add import + fix call, or fix two occurrences):
{{
  "replacements": [
    {{ "old": "<exact snippet 1>", "new": "<replacement 1>" }},
    {{ "old": "<exact snippet 2>", "new": "<replacement 2>" }}
  ],
  "risk": "low | medium | high"
}}

Rules:
- Each "old" MUST appear verbatim in the file; list them in the order they appear in the file (top to bottom) so they can be applied correctly.
- Prefer a single replacement when possible; use multiple only when necessary (e.g. adding an import and fixing the vulnerable line).
- Multi-line replacements are allowed. In JSON, represent line breaks inside the "old" and "new" strings using the escaped sequence `\\n` (example: `"new": "line1();\\nline2();"`).
- If `old` is a single line and `new` expands to multiple lines, ensure each subsequent line is indented to match the original line's indentation (the patcher also tries to preserve indentation, but this makes results more reliable).

Previous failed attempts (do NOT repeat these changes):
{failure_msg}
"""


        prompt = f"""
File: {file}

Security finding:
Rule ID: {finding.get("check_id")}
Message: {finding.get("extra", {}).get("message")}

Relevant code context (tree-sitter function scope, diff hunk, and/or line — may be partial):
{diff}
"""

        print_llm_context_if_enabled(
            f"PatchStrategy file={file}",
            sys,
            prompt,
        )

        raw = self.llm.run(sys, prompt)

        try:
            data = json.loads(raw)
        except json.JSONDecodeError:
            raise ValueError("PatchStrategy: LLM did not return valid JSON")

        risk = data.get("risk", "medium")
        if "replacements" in data:
            replacements = [(r["old"], r["new"]) for r in data["replacements"]]
        else:
            replacements = [(data["old"], data["new"])]

        if not replacements:
            raise ValueError("PatchStrategy: LLM returned no replacements")

        return PatchResult(
            file=file,
            replacements=replacements,
            risk=risk,
            requires_human=(risk != "low"),
        )

def run_cmd(self, cmd: list[str]) -> None:
        result = subprocess.run(
            cmd,
            cwd=self.repo_path,
            capture_output=True,
            text=True,
        )
        if result.returncode != 0:
            raise ValidationError(
                f"Command failed: {' '.join(cmd)}\n"
                f"STDOUT:\n{result.stdout}\n"
                f"STDERR:\n{result.stderr}"
            )

def syntax_check(self) -> None:
        for file in self.repo_path.rglob("*.cpp"):
            self.run_cmd(["g++", "-fsyntax-only", str(file)])

def syntax_check(self) -> None:
        # Do nothing — fallback if language unsupported
        pass

def syntax_check(self) -> None:
        # Compile all Python files in repo
        self.run_cmd(["python", "-m", "compileall", "."])

def get_validator(repo_path: str):
    repo = Path(repo_path)

    extensions = {p.suffix for p in repo.rglob("*") if p.is_file()}

    for ext, validator_cls in EXTENSION_MAP.items():
        if ext in extensions:
            return validator_cls(repo_path)

    return GenericValidator(repo_path)

def syntax_check(self) -> None:
        if (self.repo_path / "Cargo.toml").exists():
            self.run_cmd(["cargo", "check"])
        else:
            # Fallback: check individual files
            for file in self.repo_path.rglob("*.rs"):
                self.run_cmd(["rustc", "--emit=metadata", str(file)])
